<script setup lang="ts">
import { computed } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import Icon from '../Icon.vue'
import { NAV_GROUPS } from '../../data/nav'
import { useStore } from '../../store'

defineProps<{ collapsed: boolean }>()
defineEmits<{ (e: 'toggle'): void }>()

const route = useRoute()
const router = useRouter()
const store = useStore()

import type { NavItem } from '../../types'

function go(item: NavItem) {
  if (item.newTab) {
    window.open(item.externalPath ?? `/${item.id}`, '_blank')
  } else {
    router.push({ name: item.id })
  }
}

const user = computed(() => store.getters['auth/user'])
const initials = computed(() => store.getters['auth/initials'])

const displayName = computed(() => user.value?.name ?? 'Guest')
const displayRole = computed(() => {
  const roles: string[] = user.value?.roles ?? []
  if (roles.includes('admin')) return 'Admin'
  if (roles.includes('ACTIVE_USER')) return 'Active User'
  return 'Viewer'
})

function logout() {
  store.dispatch('auth/logout')
  router.push({ name: 'login' })
}
</script>

