      <button
        class="sidebar-collapse-btn"
        @click="$emit('toggle')"
        :title="collapsed ? 'Expand sidebar' : 'Collapse sidebar'"
        :aria-label="collapsed ? 'Expand sidebar' : 'Collapse sidebar'"
      >
        <Icon
          name="chevR"
          :size="12"
          :stroke="2.2"
          :style="{ transform: collapsed ? 'none' : 'rotate(180deg)' }"
        />
      </button>
    </div>

    <div class="nav-group" v-for="g in NAV_GROUPS" :key="g.label">
      <div class="nav-label">{{ g.label }}</div>
      <button
        v-for="it in g.items"
        :key="it.id"
        class="nav-item"
        :class="{ active: route.name === it.id }"
        @click="go(it)"
        :data-label="it.label"
        :title="collapsed ? it.label : undefined"
      >
        <Icon :name="it.icon" class="ni-icon" />
        <span>{{ it.label }}</span>
      </button>
    </div>

    <div class="sidebar-footer">
      <div class="profile-chip" @click="logout" title="Logout" style="cursor: pointer">
        <div class="avatar">{{ initials }}</div>
        <div style="flex: 1; min-width: 0">
          <div class="pc-name">{{ displayName }}</div>
          <div class="pc-role">{{ displayRole }}</div>
        </div>
        <Icon name="chev" :size="14" class="pc-chev" :style="{ color: '#6E7793' }" />
      </div>
    </div>
  </aside>
</template>
